#include <bits/stdc++.h>
using namespace std;
const int maxn=1005,kd[][2]= {0,1,1,0,0,-1,-1,0};
struct node {
	int x,y,s;
} ss;
int n,x1,yy,x2,y2;
char a[maxn][maxn];
bool s[maxn][maxn];
queue<node> e;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1; i<=n; i++)
		for(int j=1; j<=n; j++)
			cin>>a[i][j];
	cin>>x1>>yy>>x2>>y2;
	ss.x=x1,ss.y=yy,ss.s=0;
	e.push(ss);
	s[x1][yy]=1;
	while(!e.empty()) {
		int x=e.front().x,y=e.front().y;
		if(x==x2&&y==y2) cout<<e.front().s;
		for(int i=0; i<4; i++) {
			int tx=x+kd[i][0],ty=y+kd[i][1];
			if(tx>=1&&ty>=1&&tx<=n&&ty<=n&&a[tx][ty]=='0'&&!s[tx][ty]) {
				node tt;
				tt.x=tx,tt.y=ty;
				tt.s=e.front().s+1;
				e.push(tt);
				s[tx][ty]=1;
			}
		}
		e.pop();
	}
	return 0;
}
